insert into guide (categoria, titolo, corpo, ordine) values ('Quando', 'L''ora d''oro', 'Gli uccelli sono più attivi e cantano di più nelle prime ore dopo l''alba: è il momento migliore per uscire. Pianifica le uscite intorno al sorgere del sole e troverai più specie in meno tempo.', 1);
insert into guide (categoria, titolo, corpo, ordine) values ('Quando', 'Il secondo picco del tramonto', 'Prima del calare del sole c''è un secondo momento di attività, più breve dell''alba ma prezioso se non sei mattiniero. Molti uccelli tornano a nutrirsi e a cantare prima di posarsi per la notte.', 2);
insert into guide (categoria, titolo, corpo, ordine) values ('Quando', 'Esci dopo la pioggia', 'Appena smette di piovere, gli uccelli escono a nutrirsi e ad asciugarsi: è un ottimo momento per osservarli. Cerca vicino alle pozze e sui rami esposti al sole.', 3);
insert into guide (categoria, titolo, corpo, ordine) values ('Quando', 'Cerca le giornate senza vento', 'Con il vento forte gli uccelli si nascondono e diventano difficili da sentire e da vedere. Le giornate calme e limpide sono le più produttive.', 4);
insert into guide (categoria, titolo, corpo, ordine) values ('Quando', 'Le mezze stagioni sono d''oro', 'Primavera e autunno sono i periodi della migrazione: passano specie che il resto dell''anno non incontri. Tieni d''occhio il tuo territorio proprio in questi mesi.', 5);
insert into guide (categoria, titolo, corpo, ordine) values ('Dove', 'Punta sulle zone di margine', 'I confini tra ambienti diversi – dove il bosco incontra il prato, o la siepe il campo – sono i più ricchi di uccelli. Cammina lungo questi bordi invece che dentro un ambiente uniforme.', 6);
insert into guide (categoria, titolo, corpo, ordine) values ('Dove', 'L''acqua attira tutto', 'Uno stagno, un ruscello, persino una grande pozza raccolgono uccelli di molte specie, soprattutto d''estate. Trova l''acqua e avrai trovato gli uccelli.', 7);
insert into guide (categoria, titolo, corpo, ordine) values ('Dove', 'Non serve andare lontano', 'Parchi urbani, giardini e persino i tetti ospitano più specie di quanto immagini. Allena l''occhio vicino a casa prima di cercare mete esotiche.', 8);
insert into guide (categoria, titolo, corpo, ordine) values ('Dove', 'Segui il cibo', 'Un albero carico di bacche o in fiore è una calamita per gli uccelli. Individua le piante che stanno fruttificando e appostati lì con calma.', 9);
insert into guide (categoria, titolo, corpo, ordine) values ('Dove', 'Le tappe dei migratori', 'Durante la migrazione, coste, zone umide e laghi diventano soste affollate. Sono i posti giusti per vedere specie di passaggio che altrove non compaiono.', 10);
insert into guide (categoria, titolo, corpo, ordine) values ('Tecnica', 'Fatti piccolo e silenzioso', 'Muoviti lentamente, evita colori sgargianti e non puntare mai dritto verso l''uccello: avvicinati di lato e fermati spesso. Spesso è più efficace restare immobili vicino a un cespuglio e lasciare che siano loro ad avvicinarsi.', 11);
insert into guide (categoria, titolo, corpo, ordine) values ('Tecnica', 'Tieni il sole alle spalle', 'Con il sole dietro di te vedrai i colori veri dell''uccello, non una sagoma controluce. Bastano pochi passi per avere la luce dalla parte giusta.', 12);
insert into guide (categoria, titolo, corpo, ordine) values ('Tecnica', 'Cammina, fermati, osserva', 'Molti uccelli li scopri solo quando ti fermi: il movimento continuo li mette in allarme e copre i loro suoni. Alterna pochi passi a lunghe pause di ascolto e osservazione.', 13);
insert into guide (categoria, titolo, corpo, ordine) values ('Tecnica', 'Cerca il movimento, non l''uccello', 'Un uccello fermo è quasi invisibile; un uccello che si muove tradisce la sua posizione. Allena l''occhio a cogliere il guizzo tra le foglie più che la forma intera.', 14);
insert into guide (categoria, titolo, corpo, ordine) values ('Tecnica', 'Prima gli occhi, poi il binocolo', 'Individua l''uccello a occhio nudo e tieni lo sguardo fisso su di lui, poi porta il binocolo agli occhi senza abbassare la testa. Cercarlo direttamente col binocolo è il modo più rapido per perderlo.', 15);
insert into guide (categoria, titolo, corpo, ordine) values ('Ascolto', 'Impara ad ascoltare', 'Molti uccelli si sentono prima di vederli: l''orecchio conta quanto l''occhio. Quando senti un canto che non riconosci, registralo con l''app e lascia che sia lei a dirti chi è.', 16);
insert into guide (categoria, titolo, corpo, ordine) values ('Ascolto', 'Un canto alla volta', 'Non cercare di imparare tutti i richiami insieme: parti da quattro o cinque uccelli comuni del tuo giardino e fissali bene. Da lì costruirai il resto molto più in fretta.', 17);
insert into guide (categoria, titolo, corpo, ordine) values ('Ascolto', 'Registra e riascolta', 'Ogni registrazione che salvi è un piccolo ripasso: riascoltare i canti raccolti allena l''orecchio meglio di qualsiasi manuale. Col tempo riconoscerai le voci senza nemmeno alzare lo sguardo.', 18);
insert into guide (categoria, titolo, corpo, ordine) values ('Identificazione', 'Prima la forma, poi il colore', 'La sagoma, le proporzioni e il portamento dicono più del colore, che cambia con la luce. Guarda la forma del corpo, del becco e della coda prima di ogni altra cosa.', 19);
insert into guide (categoria, titolo, corpo, ordine) values ('Identificazione', 'Usa le taglie di riferimento', 'Chiediti se è più piccolo di un passero, grande come un merlo o come un piccione: il confronto con specie che conosci è la tua bussola. La taglia esatta inganna, il paragone no.', 20);
insert into guide (categoria, titolo, corpo, ordine) values ('Identificazione', 'Il modo di volare è un indizio', 'Volo ondulato, battuto o planato: ogni gruppo di uccelli si muove in cielo a modo suo. Osservare il volo aiuta a riconoscere anche una sagoma lontana.', 21);
insert into guide (categoria, titolo, corpo, ordine) values ('Identificazione', 'Prendi appunti sul campo', 'Annota taglia, colori, becco, comportamento e ambiente mentre l''uccello è davanti a te, non dopo. I dettagli sfumano in fretta dalla memoria, ed è proprio da quelli che nasce l''identificazione.', 22);
insert into guide (categoria, titolo, corpo, ordine) values ('Attrezzatura', 'Il binocolo prima di tutto', 'Un buon binocolo conta più di una macchina fotografica costosa: è il primo acquisto da fare. Per iniziare, un 8x42 è il compromesso ideale tra ingrandimento e luminosità.', 23);
insert into guide (categoria, titolo, corpo, ordine) values ('Attrezzatura', 'Regola bene il binocolo', 'Imposta la distanza tra gli oculari sulla larghezza dei tuoi occhi e correggi la messa a fuoco con la rotella diottrica. Un binocolo regolato male stanca la vista e fa perdere dettagli.', 24);
insert into guide (categoria, titolo, corpo, ordine) values ('Attrezzatura', 'Vestiti a strati e in colori neutri', 'Verde, marrone e grigio ti fanno passare inosservato; i colori accesi mettono in allarme gli uccelli. Gli strati ti permettono di stare fermo a lungo senza soffrire il freddo.', 25);
insert into guide (categoria, titolo, corpo, ordine) values ('Etica', 'Osserva con rispetto', 'Tieni le distanze dai nidi e non disturbare gli uccelli per una foto migliore. Il birdwatching bello è quello che lascia l''uccello indisturbato.', 26);
insert into guide (categoria, titolo, corpo, ordine) values ('Etica', 'Non mettere in fuga gli uccelli', 'Se un uccello smette di nutrirsi e ti fissa, sei troppo vicino: arretra. Costringerlo a volare via gli fa sprecare energie preziose, soprattutto d''inverno.', 27);
insert into guide (categoria, titolo, corpo, ordine) values ('Etica', 'Evita di abusare dei richiami', 'Riprodurre in continuazione i richiami registrati per attirare gli uccelli li stressa e li distrae dalle loro attività. Usali con parsimonia, o non usarli affatto.', 28);
insert into guide (categoria, titolo, corpo, ordine) values ('Etica', 'Rispetta sentieri e proprietà', 'Resta sui percorsi, chiedi permesso sui terreni privati e non calpestare la vegetazione per avvicinarti. Un buon osservatore lascia l''ambiente come l''ha trovato.', 29);
insert into guide (categoria, titolo, corpo, ordine) values ('Giardino', 'Metti una vaschetta d''acqua', 'Una bacinella d''acqua pulita attira più uccelli di molte mangiatoie, soprattutto nelle estati calde. Cambiala spesso e tienila a riparo dai gatti.', 30);
insert into guide (categoria, titolo, corpo, ordine) values ('Giardino', 'Pianta specie autoctone', 'Gli arbusti e gli alberi del posto offrono agli uccelli il cibo e il riparo a cui sono abituati. Un giardino con piante nostrane attira molte più specie di uno solo ornamentale.', 31);
insert into guide (categoria, titolo, corpo, ordine) values ('Giardino', 'Tieni pulite le mangiatoie', 'Una mangiatoia sporca diffonde malattie tra gli uccelli: puliscila e disinfettala regolarmente. Meglio nessuna mangiatoia che una trascurata.', 32);
insert into guide (categoria, titolo, corpo, ordine) values ('Stagioni', 'L''inverno è la stagione del principiante', 'Con gli alberi spogli gli uccelli sono più facili da vedere, e le mangiatoie li portano vicino a te. È il periodo migliore per iniziare e imparare le specie comuni.', 33);
insert into guide (categoria, titolo, corpo, ordine) values ('Stagioni', 'Segui la migrazione', 'In autunno e primavera annota le prime e le ultime volte che vedi una specie: capirai i ritmi del tuo territorio. Da un anno all''altro riconoscerai chi arriva e chi parte.', 34);
insert into guide (categoria, titolo, corpo, ordine) values ('L''app', 'Segna sempre dove', 'Registrare il luogo di ogni avvistamento riempie la tua mappa e, col tempo, ti mostra dove ritrovare ogni specie. È il tuo diario di campo, sempre in tasca.', 35);
insert into guide (categoria, titolo, corpo, ordine) values ('L''app', 'Costruisci la tua life list', 'Ogni specie nuova che aggiungi alla collezione entra nella tua "lista della vita": vederla crescere è metà del divertimento. Crea raccolte per uscita o per luogo per ritrovare facilmente i tuoi ricordi.', 36);
